#include <stdio.h>
#include <stdlib.h>

int rank_of(char c){
    const char order[] = {'!','#','$','%','&','*','?','@','^'};
    for(int i=0;i<9;++i) if(order[i]==c) return i;
    return -1;
}
int cmp(const void *a,const void *b){
    char ca=*(const char*)a, cb=*(const char*)b;
    return rank_of(ca)-rank_of(cb);
}
