import java.io.*;
import java.util.*;
public class Main {
    private static final char[] ORDER = {'!','#','$','%','&','*','?','@','^'};
    private static final Map<Character,Integer> RANK = new HashMap<>();
    static{
        for(int i=0;i<ORDER.length;i++) RANK.put(ORDER[i],i);
    }
    private static void sort(char[] arr){
        Character[] tmp = new Character[arr.length];
        for(int i=0;i<arr.length;i++) tmp[i]=arr[i];
        Arrays.sort(tmp, Comparator.comparingInt(RANK::get));
        for(int i=0;i<arr.length;i++) arr[i]=tmp[i];
    }
    public static void main(String[] args) throws Exception{
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while(T-- > 0){
            int N = Integer.parseInt(br.readLine().trim());
            st = new StringTokenizer(br.readLine());
            char[] nuts = new char[N];
            for(int i=0;i<N;i++) nuts[i]=st.nextToken().charAt(0);
            st = new StringTokenizer(br.readLine());
            char[] bolts = new char[N];
            for(int i=0;i<N;i++) bolts[i]=st.nextToken().charAt(0);
            sort(nuts);
            sort(bolts);
            for(int i=0;i<N;i++){
                out.append(nuts[i]);
                if(i+1<N) out.append(' ');
            }
            out.append('\n');
            for(int i=0;i<N;i++){
                out.append(bolts[i]);
                if(i+1<N) out.append(' ');
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

